extends Resource
class_name EnemyStats

@export var name: String = ""
@export var max_health: int = 100
@export var speed: float = 100.0
@export var damage: int = 10
@export var color: Color = Color.WHITE

extends CharacterBody2D

@export var stats: EnemyStats

var current_health: int = 0

func _ready() -> void:
	if stats == null:
		return
	current_health = stats.max_health
	var rect := $ColorRect as ColorRect
	if rect != null:
		rect.color = stats.color


func take_damage(amount: int) -> void:
	current_health -= amount
	if current_health <= 0:
		queue_free()

extends Node2D

@export var enemy_types: Array[EnemyStats] = []

const ENEMY_SCENE := preload("res://scenes/Enemy.tscn")

func _ready() -> void:
	for i in enemy_types.size():
		var enemy: CharacterBody2D = ENEMY_SCENE.instantiate()
		enemy.stats = enemy_types[i]
		enemy.position = Vector2(i * 64.0, 0.0)
		add_child(enemy)


func take_damage_all(amount: int) -> void:
	for child in get_children():
		if child.has_method("take_damage"):
			child.take_damage(amount)

